#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <limits>

bool isEven(int num);

int main() {
    std::vector<std::pair<int, bool>> testCases = {
        {4, true},
        {7, false},
        {0, true},
        {-2, true},
        {-3, false},
        {100, true},
        {99, false},
        {-100, true},
        {-99, false}
    };

    int min_int = std::numeric_limits<int>::min();
    testCases.push_back({min_int, true});

    std::cout << std::boolalpha;

    for (const auto& tc : testCases) {
        int input = tc.first;
        bool expected = tc.second;
        bool actual = isEven(input);
        std::cout << "Input: " << input
                  << ", Expected: " << expected
                  << ", Actual: " << actual;
        if (actual == expected) {
            std::cout << " [PASSED]\n";
        } else {
            std::cout << " [FAILED]\n";
        }
    }

    return 0;
}
